import{_ as r,y as o,a,o as n,a2 as t,D as l}from"./chunks/framework.DCcmcJcL.js";const _=JSON.parse('{"title":"Customer Management","description":"","frontmatter":{},"headers":[],"relativePath":"multi-vendor-marketplace/customer-management.md","filePath":"multi-vendor-marketplace/customer-management.md","lastUpdated":1782394364000}'),i={name:"multi-vendor-marketplace/customer-management.md"};function m(h,e,u,c,d,g){const s=o("ImagePopup");return n(),a("div",null,[e[0]||(e[0]=t('<h1 id="customer-management" tabindex="-1">Customer Management <a class="header-anchor" href="#customer-management" aria-label="Permalink to &quot;Customer Management&quot;">​</a></h1><p>The Customers section gives sellers visibility into the buyers who have purchased from their store. It helps sellers understand who their customers are and how valuable they are, supporting better service and follow-up.</p><h3 id="where-to-find-it" tabindex="-1">Where to find it <a class="header-anchor" href="#where-to-find-it" aria-label="Permalink to &quot;Where to find it&quot;">​</a></h3><p>From the seller panel, open the <strong>Customers</strong> menu.</p><p>The page lists the seller&#39;s customers in a searchable, sortable DataGrid showing key details such as:</p><ul><li><strong>Name</strong> — the customer&#39;s name.</li><li><strong>Email</strong> — the customer&#39;s email address.</li><li><strong>Gender</strong> — the customer&#39;s gender (if provided).</li><li><strong>Group</strong> — the customer group they belong to.</li><li><strong>Orders</strong> — the number of orders the customer has placed with this seller.</li><li><strong>Revenue</strong> — the total revenue the customer has generated for this seller.</li></ul>',6)),l(s,{src:"/images/multi-vendor-marketplace/seller-customers.png",alt:"Seller Customers"}),e[1]||(e[1]=t('<h3 id="using-the-list" tabindex="-1">Using the list <a class="header-anchor" href="#using-the-list" aria-label="Permalink to &quot;Using the list&quot;">​</a></h3><p>Sellers can filter and sort the list to identify their most active or highest-value customers, then use the marketplace <strong>Communication</strong> feature to message them directly when needed.</p><blockquote><p><strong>Availability:</strong> Seller access to customer details is controlled by the admin configuration <strong>Seller → Can View Customers</strong>. If the admin disables it, the Customers section is not available to sellers.</p></blockquote><blockquote><p><strong>Note:</strong> Each seller sees only the customers who have ordered from their own store; customer data is always scoped to the seller.</p></blockquote>',4))])}const f=r(i,[["render",m]]);export{_ as __pageData,f as default};
